const resp = $.steps.searchKnowledgeBase.response || {};
const data = resp.data || resp;
const results = data.results || [];

let context = '';
const sources = [];

results.slice(0, 5).forEach((r, i) => {
  const title = r.title || 'Untitled';
  const url = r.url || '';
  const text = (r.text || '').slice(0, 2000);
  context += '=== SOURCE ' + (i + 1) + ' ===\n';
  context += 'Title: ' + title + '\n';
  context += 'URL: ' + url + '\n';
  context += 'Content: ' + text + '\n\n';
  sources.push({ title, url });
});

return { context, sources, sourceCount: results.length };

const question = $.input.question;
const domain = $.input.knowledgeDomain || 'IT operations';
const searchData = $.steps.parseSearchResults.output;

let prompt = 'You are a senior IT operations specialist with deep expertise in ' + domain + '. Answer the following IT question using the knowledge base sources provided.\n\n';
prompt += 'QUESTION: ' + question + '\n\n';
prompt += 'KNOWLEDGE BASE SOURCES:\n' + searchData.context + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Provide a clear, actionable answer\n';
prompt += '- Include step-by-step instructions where applicable\n';
prompt += '- Reference sources when citing specific information\n';
prompt += '- If the sources are insufficient, say so and provide general best practices\n';
prompt += '- Include any warnings or caveats for the recommended approach\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "Clear answer text with markdown formatting",\n';
prompt += '  "steps": ["Step 1 description", "Step 2 description"],\n';
prompt += '  "warnings": ["any important warnings"],\n';
prompt += '  "confidence": "high/medium/low",\n';
prompt += '  "category": "networking/security/hardware/software/other",\n';
prompt += '  "relatedTopics": ["related topic for further reading"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnswer.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, steps: [], warnings: [], confidence: 'medium', category: 'other', relatedTopics: [] }; }

const ai = $.steps.parseAI.output;
const sources = $.steps.parseSearchResults.output.sources;
const question = $.input.question;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'IT Support Answer', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Category:*\n' + (ai.category || 'General') },
  { type: 'mrkdwn', text: '*Confidence:*\n' + (ai.confidence || 'N/A') }
] });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No answer generated.').slice(0, 2500);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Answer:*\n' + answerText } });

if (ai.steps && ai.steps.length > 0) {
  blocks.push({ type: 'divider' });
  let stepsText = '*Steps:*\n';
  ai.steps.forEach((s, i) => { stepsText += (i + 1) + '. ' + s + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: stepsText.slice(0, 1800) } });
}

if (ai.warnings && ai.warnings.length > 0) {
  let warnText = '*:warning: Warnings:*\n';
  ai.warnings.forEach(w => { warnText += '- ' + w + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: warnText.slice(0, 1000) } });
}

if (sources && sources.length > 0) {
  blocks.push({ type: 'divider' });
  let srcText = '*Sources:*\n';
  sources.slice(0, 3).forEach((s, i) => {
    srcText += (i + 1) + '. <' + s.url + '|' + s.title + '>\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText.slice(0, 1000) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa Search + Claude AI + One CLI' }] });

const fallback = 'IT Answer [' + (ai.category || '') + ']: ' + (ai.answer || '').slice(0, 100);
return { blocks, fallback };
